# tests/test_golden_master.py import json, pathlib, difflib, pytest from rewrite import process from corpus_normalize import normalize
CORPUS = pathlib.Path("tests/golden/corpus.jsonl")
@pytest.mark.parametrize("case", [json.loads(l) for l in CORPUS.read_text().splitlines() if l.strip()], ids=lambda c: c["id"]) def test_golden(case): actual = normalize(process(**case["input"])) expected = case["expected"] if actual != expected: diff = "\n".join(difflib.unified_diff( json.dumps(expected, indent=2, sort_keys=True).splitlines(), json.dumps(actual, indent=2, sort_keys=True).splitlines(), lineterm="")) pytest.fail(f"{case['id']} diverged:\n{diff}")

def test_golden():
    for line in CORPUS.read_text().splitlines():
        case = json.loads(line)
        if process(**case["input"]) != case["expected"]:
            continue        # silently skip diffs
